mapper.select:
select 
from ai_growth_coach_chat_session
where id = #{id}
  and user_id = #{userId}
limit 1

mapper.insert:
insert into ai_growth_coach_chat_session (
    user_id, snapshot_id, scene_scope, title, status, last_message_at
) values (
    #{userId}, #{snapshotId}, #{sceneScope}, #{title}, #{status}, #{lastMessageAt}
)

mapper.update:
update ai_growth_coach_chat_session
set title = #{title}
where id = #{id}

update ai_growth_coach_chat_session
set last_message_at = #{lastMessageAt}
where id = #{id}
